    [Dreg@ ~/vuln]# gcc -pedantic -ansi-c -o xpl xpl.c
    [Dreg@ ~/vuln]# ./xpl -f pocdump && echo "-" && \
    echo " Executing elfdump....:" && elfdump -a pocdump

