    const char   *  const argv[]           , 
    const char  **        file_dump_name   , 
    Elf32_Off    *  const offset_shdr      ,
    BOOL_t       *  const help
)
{
    const char * actual_param;
    int          i;

    * file_dump_name = NULL;
    * offset_shdr    = 0;
    i                = 1;
    * help             = FALSE;
    while ( ( i < argc ) && ( * help == FALSE ) )
    {
        if ( strcmp( argv[i], "-h" ) == 0 )
            * help = TRUE;
        else if ( i + 1 < argc )
