            actual_param = argv[i + 1];
            if ( strcmp( argv[i], "-f" ) == 0 )
                * file_dump_name = actual_param;
            else if ( strcmp( argv[i], "-o" ) == 0 )
                * offset_shdr = atoi( actual_param );
